const { execSync } = require('child_process');
const path = require('path');

// 切换到脚本所在目录
process.chdir(path.dirname(process.argv[1]));

try {
  // 检查最近 10 分钟的邮件
  const emailsOutput = execSync('node scripts/imap.js check --recent 10m --limit 50', {
    encoding: 'utf-8'
  });

  console.log('邮件检查结果:');
  console.log(emailsOutput);

  // 尝试解析 JSON
  try {
    const emails = JSON.parse(emailsOutput);
    console.log('\n解析成功，共收到', emails.length, '封邮件');

    // 检测紧急邮件
    const urgentKeywords = ['紧急', '重要', 'urgent', 'asap', 'immediately', 'deadline', '截止', '会议', 'meeting'];
    const urgentEmails = emails.filter(email => {
      const subject = (email.subject || '').toLowerCase();
      const body = (email.body || '').toLowerCase();
      return urgentKeywords.some(keyword => 
        subject.includes(keyword.toLowerCase()) || body.includes(keyword.toLowerCase())
      );
    });

    if (urgentEmails.length > 0) {
      console.log('\n发现', urgentEmails.length, '封紧急邮件');
      urgentEmails.forEach(email => {
        console.log(`- 主题：${email.subject}`);
        console.log(`  发件人：${email.from}`);
        console.log(`  时间：${email.date}`);
      });
    } else {
      console.log('\n没有发现紧急邮件');
    }
  } catch (e) {
    console.log('无法解析为 JSON，可能是没有邮件');
  }
} catch (error) {
  console.error('执行出错:', error.message);
  if (error.stdout) console.log('stdout:', error.stdout.toString());
  if (error.stderr) console.log('stderr:', error.stderr.toString());
}

